async function importHistorique() {
  console.log(`\n📊 Import de ${data.length} jours de CA dans Supabase...\n`)

  let success = 0
  let errors = 0
  let skipped = 0

  for (const row of data) {
    const { error } = await supabase
      .from('historique_ca')
      .upsert({
        date: row.date,
        ca_brut: row.ca_brut,
        ca_ht: row.ca_ht,
        especes: row.especes,
        cb: row.cb,
        tpa: row.tpa,
        tr: row.tr,
        uber: row.uber,
        commission_uber: row.commission_uber,
        nb_commandes: row.nb_commandes,
      }, { onConflict: 'date' })

    if (error) {
      errors++
      if (errors <= 3) console.error('❌', row.date, error.message)
    } else {
      success++
      if (success % 50 === 0) console.log(`✅ ${success}/${data.length} lignes importées...`)
    }
  }

  console.log(`\n🎉 Import terminé !`)
  console.log(`✅ ${success} lignes importées`)
  console.log(`⏭️  ${skipped} doublons ignorés`)
  if (errors > 0) console.log(`❌ ${errors} erreurs`)

  // Vérification
  const { count } = await supabase.from('historique_ca').select('*', { count: 'exact', head: true })
  console.log(`\n📈 Total dans Supabase : ${count} jours`)
}

importHistorique()
